import java.util.concurrent.locks.*;
import java.util.concurrent.*;
import java.util.*;

public class ReentrantLockDemo {

    // ── Bounded blocking queue using ReentrantLock + 2 Conditions ──
    static class BoundedQueue<T> {
        private final Queue<T> queue = new LinkedList<>();
        private final int capacity;
        private final ReentrantLock lock = new ReentrantLock();
        private final Condition notFull  = lock.newCondition(); // signal when space available
        private final Condition notEmpty = lock.newCondition(); // signal when item available

        BoundedQueue(int capacity) { this.capacity = capacity; }

        public void put(T item) throws InterruptedException {
            lock.lock();
            try {
                while (queue.size() == capacity)
                    notFull.await(); // release lock and wait
                queue.add(item);
                notEmpty.signal(); // wake a waiting consumer
            } finally {
                lock.unlock(); // ALWAYS in finally
            }
        }

        public T take() throws InterruptedException {
            lock.lock();
            try {
                while (queue.isEmpty())
                    notEmpty.await();
                T item = queue.poll();
                notFull.signal(); // wake a waiting producer
                return item;
            } finally {
                lock.unlock();
            }
        }
    }

    // ── tryLock: avoid deadlock by backing off ────────────────────
    static ReentrantLock lock1 = new ReentrantLock();
    static ReentrantLock lock2 = new ReentrantLock();

    static boolean transferWithBackoff() throws InterruptedException {
        while (true) {
            if (lock1.tryLock(50, TimeUnit.MILLISECONDS)) {
                try {
                    if (lock2.tryLock(50, TimeUnit.MILLISECONDS)) {
                        try {
                            System.out.println("Both locks acquired — transfer done");
                            return true;
                        } finally { lock2.unlock(); }
                    }
                } finally { lock1.unlock(); }
            }
            Thread.sleep(10 + (long)(Math.random() * 20)); // back off
        }
    }

    public static void main(String[] args) throws Exception {
        BoundedQueue<Integer> bq = new BoundedQueue<>(3);

        Thread producer = new Thread(() -> {
            try {
                for (int i = 1; i <= 5; i++) {
                    bq.put(i);
                    System.out.println("Put: " + i);
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        Thread consumer = new Thread(() -> {
            try {
                for (int i = 0; i < 5; i++) {
                    Thread.sleep(100);
                    System.out.println("Got: " + bq.take());
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        producer.start(); consumer.start();
        producer.join(); consumer.join();

        transferWithBackoff();
    }
}

import java.util.concurrent.*;
import java.util.concurrent.locks.*;
import java.util.*;

public class ReadWriteLockAndSemaphore {

    // ── ReadWriteLock: Thread-safe cache ──────────────────────────
    static class Cache<K, V> {
        private final Map<K, V> map = new HashMap<>();
        private final ReadWriteLock rwl = new ReentrantReadWriteLock();
        private final Lock readLock  = rwl.readLock();
        private final Lock writeLock = rwl.writeLock();

        public V get(K key) {
            readLock.lock(); // multiple threads can read simultaneously
            try {
                return map.get(key);
            } finally {
                readLock.unlock();
            }
        }

        public void put(K key, V value) {
            writeLock.lock(); // exclusive: all reads block during write
            try {
                map.put(key, value);
            } finally {
                writeLock.unlock();
            }
        }

        public int size() {
            readLock.lock();
            try { return map.size(); }
            finally { readLock.unlock(); }
        }
    }

    // ── Semaphore: Connection Pool ────────────────────────────────
    static class ConnectionPool {
        private final Semaphore semaphore;
        private final Queue<String> connections = new ConcurrentLinkedQueue<>();

        ConnectionPool(int size) {
            this.semaphore = new Semaphore(size, true); // fair
            for (int i = 1; i <= size; i++) connections.add("conn-" + i);
        }

        public String acquire(long timeout, TimeUnit unit) throws InterruptedException {
            if (!semaphore.tryAcquire(timeout, unit))
                throw new RuntimeException("Timeout: no connection available");
            return connections.poll();
        }

        public void release(String conn) {
            connections.add(conn);
            semaphore.release();
        }
    }

    public static void main(String[] args) throws Exception {
        Cache<String, Integer> cache = new Cache<>();
        cache.put("hits", 100);

        // Many readers simultaneously
        ExecutorService pool = Executors.newFixedThreadPool(4);
        for (int i = 0; i < 4; i++) {
            pool.submit(() -> System.out.println(Thread.currentThread().getName()
                + " reads: " + cache.get("hits")));
        }
        pool.shutdown();
        pool.awaitTermination(1, TimeUnit.SECONDS);

        ConnectionPool cp = new ConnectionPool(2);
        String c1 = cp.acquire(1, TimeUnit.SECONDS);
        String c2 = cp.acquire(1, TimeUnit.SECONDS);
        System.out.println("Acquired: " + c1 + ", " + c2);
        cp.release(c1);
        String c3 = cp.acquire(1, TimeUnit.SECONDS);
        System.out.println("After release, acquired: " + c3);
        cp.release(c2); cp.release(c3);
    }
}

problems.description:
Implement a thread-safe counter using `ReentrantLock` explicitly (instead of `synchronized`).

**Example:**
ReentrantLock lock = new ReentrantLock();
void increment() {
    lock.lock();
    try { count++; }
    finally { lock.unlock(); } // always unlock in finally!
}
10 threads * 1000 increments => count = 10000

**Key insight:** Always unlock in `finally` — if an exception occurs between lock and unlock, the lock would be held forever.

