import java.util.concurrent.*;
import java.util.*;

public class Q3 {
    static class ResourcePool<T> {
        private final Semaphore semaphore;
        private final Queue<T> resources = new ConcurrentLinkedQueue<>();

        public ResourcePool(List<T> items) {
            this.semaphore = new Semaphore(items.size(), true);
            resources.addAll(items);
        }

        public T acquire() throws InterruptedException {
            semaphore.acquire();
            return resources.poll();
        }

        public void release(T resource) {
            resources.add(resource);
            semaphore.release();
        }
    }

    public static void main(String[] args) throws Exception {
        ResourcePool<String> pool = new ResourcePool<>(Arrays.asList("R1", "R2"));
        String r1 = pool.acquire();
        String r2 = pool.acquire();
        System.out.println("Got: " + r1 + ", " + r2);
        pool.release(r1);
        String r3 = pool.acquire();
        System.out.println("After release, got: " + r3);
        pool.release(r2); pool.release(r3);
        System.out.println("Done");
    }
}
